import { useRef, useState } from 'react'
import { useParams } from 'react-router-dom'
import html2canvas from 'html2canvas'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const mockupRef = useRef(null)

  /*
    =========================
    DEV MODE
    =========================
  */

  const DEV_MODE = true

  /*
    =========================
    PIXELS PER INCH
    =========================
  */

  const PIXELS_PER_INCH = 20

  const { id } = useParams()

  const product =
    printProducts.find(
      item => item.id === id
    )

  /*
    =========================
    FRONT LOCKED
    FINAL LOCK
    =========================
  */

  const FRONT_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5,

    zoom: 100
  }

  /*
    =========================
    LEFT CHEST LOCKED
    MOVED RIGHT .2%
    MOVED DOWN .2%
    =========================
  */

  const LEFT_CHEST_PRESET = {

    x: 57.45,
    y: 28.7,

    widthInches: 3.5,
    heightInches: 3.25,

    zoom: 100
  }

  /*
    =========================
    BACK LOCKED
    FINAL LOCK
    =========================
  */

  const BACK_PRESET = {

    x: 50.25,
    y: 41.5,

    widthInches: 11.5,
    heightInches: 11.5,

    zoom: 100
  }

  /*
    =========================
    TRUE LOCKED PRESETS
    =========================
  */

  const presetMap = {

    front:
      FRONT_PRESET,

    'left-chest':
      LEFT_CHEST_PRESET,

    back:
      BACK_PRESET
  }

  const [selectedColor, setSelectedColor] =
    useState(
      product.colors[0]
    )

  const [uploadedLogo, setUploadedLogo] =
    useState(null)

  const [activePreset, setActivePreset] =
    useState('front')

  const [dragEnabled, setDragEnabled] =
    useState(false)

  const [isDragging, setIsDragging] =
    useState(false)

  const [logoScale, setLogoScale] =
    useState(100)

  const currentPreset =
    presetMap[activePreset]

  const [customPosition, setCustomPosition] =
    useState({

      x:
        FRONT_PRESET.x,

      y:
        FRONT_PRESET.y
    })

  /*
    =========================
    INCHES TO PIXELS
    =========================
  */

  const currentWidthPx =
    currentPreset.widthInches *
    PIXELS_PER_INCH

  const currentHeightPx =
    currentPreset.heightInches *
    PIXELS_PER_INCH

  const handleUpload = (e) => {

    const file =
      e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    setUploadedLogo(
      imageUrl
    )
  }

  const setPreset = (type) => {

    setActivePreset(type)

    const preset =
      presetMap[type]

    setCustomPosition({

      x: preset.x,
      y: preset.y
    })

    setLogoScale(
      preset.zoom
    )
  }

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  const exportMockup = async () => {

    const canvas =
      await html2canvas(
        mockupRef.current,
        {
          backgroundColor: null,
          scale: 3,
          useCORS: true
        }
      )

    const image =
      canvas.toDataURL(
        'image/png'
      )

    const link =
      document.createElement(
        'a'
      )

    link.href = image

    link.download =
      `mockup-${activePreset}.png`

    link.click()
  }

  const handleMouseMove = (e) => {

    if (
      !dragEnabled ||
      !isDragging
    ) return

    const rect =
      e.target.getBoundingClientRect()

    const x =
      (
        (
          e.clientX -
          rect.left
        ) /
        rect.width
      ) * 100

    const y =
      (
        (
          e.clientY -
          rect.top
        ) /
        rect.height
      ) * 100

    const limitedX =
      Math.max(
        10,
        Math.min(90, x)
      )

    const limitedY =
      Math.max(
        10,
        Math.min(90, y)
      )

    setCustomPosition({

      x: limitedX,
      y: limitedY
    })
  }

  return (

    <div
      className="h-screen bg-black text-white overflow-hidden"
      onMouseMove={
        handleMouseMove
      }
      onMouseUp={() =>
        setIsDragging(false)
      }
    >

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        {/* MOCKUP AREA */}

        <div
          ref={mockupRef}
          className="bg-[#e9e9e9] flex items-center justify-center relative p-10 w-full h-full overflow-hidden"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[700px] max-h-[88vh] object-contain"
          />

          {/* PRINT AREA */}

          <div
            className={`absolute flex items-start justify-center ${
              dragEnabled
                ? 'cursor-move'
                : ''
            }`}
            style={{

              width:
                `${currentWidthPx}px`,

              height:
                `${currentHeightPx}px`,

              top:
                `${customPosition.y}%`,

              left:
                `${customPosition.x}%`,

              transform:
                'translate(-50%, -50%)',

              overflow: 'hidden',

              border:
                DEV_MODE
                  ? '2px solid #ff2b2b'
                  : 'none'
            }}
            onMouseDown={() => {

              if (
                dragEnabled
              ) {

                setIsDragging(true)
              }
            }}
          >

            {uploadedLogo && (

              <img
                src={uploadedLogo}
                alt="logo"
                className="select-none pointer-events-none"
                style={{

                  width: '100%',

                  height: 'auto',

                  maxHeight: '100%',

                  objectFit: 'contain',

                  transform: `
                    scale(${logoScale / 100})
                  `,

                  transformOrigin:
                    'top center'
                }}
                draggable={false}
              />

            )}

          </div>

        </div>

        {/* CONTROL PANEL */}

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          <div className="p-6 space-y-6">

            {/* COLORS */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map(
                  (color) => (

                    <button
                      key={color.name}
                      onClick={() =>
                        setSelectedColor(
                          color
                        )
                      }
                      className={`p-4 rounded-xl text-xs font-black capitalize ${
                        selectedColor.name ===
                        color.name
                          ? 'bg-yellow-500 text-black'
                          : 'bg-[#111] border border-[#222]'
                      }`}
                    >
                      {color.name}
                    </button>

                  ))}

              </div>

            </div>

            {/* PRESETS */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-1 gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() =>
                      setPreset(item)
                    }
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>

            {/* LIVE MEASUREMENTS */}

            <div className="bg-[#111] border border-[#222] rounded-xl p-4 space-y-2">

              <p className="text-xs text-yellow-500 font-black uppercase">
                Print Area
              </p>

              <div className="flex justify-between text-sm">

                <span className="text-white/60">
                  Width
                </span>

                <span className="font-black">
                  {currentPreset.widthInches}"
                </span>

              </div>

              <div className="flex justify-between text-sm">

                <span className="text-white/60">
                  Height
                </span>

                <span className="font-black">
                  {currentPreset.heightInches}"
                </span>

              </div>

            </div>

            {/* CENTER BUTTONS */}

            <div className="grid grid-cols-2 gap-3">

              <button
                onClick={() =>
                  setCustomPosition(prev => ({

                    ...prev,
                    x: 50
                  }))
                }
                className="bg-[#111] border border-[#222] py-4 rounded-xl text-xs font-black"
              >
                CENTER X
              </button>

              <button
                onClick={() =>
                  setCustomPosition(prev => ({

                    ...prev,
                    y: 50
                  }))
                }
                className="bg-[#111] border border-[#222] py-4 rounded-xl text-xs font-black"
              >
                CENTER Y
              </button>

            </div>

            {/* DRAG MODE */}

            <button
              onClick={() =>
                setDragEnabled(
                  !dragEnabled
                )
              }
              className={`w-full py-4 rounded-xl text-xs font-black ${
                dragEnabled
                  ? 'bg-yellow-500 text-black'
                  : 'bg-[#111] border border-[#222]'
              }`}
            >
              {dragEnabled
                ? 'DRAG MODE ON'
                : 'DRAG MODE OFF'}
            </button>

            {/* UPLOAD */}

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={
                  handleUpload
                }
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>

            {/* ACTIONS */}

            {uploadedLogo && (

              <>

                <button
                  onClick={
                    removeLogo
                  }
                  className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
                >
                  REMOVE LOGO
                </button>

                <button
                  onClick={
                    exportMockup
                  }
                  className="w-full bg-white text-black py-4 rounded-xl text-xs font-black"
                >
                  EXPORT MOCKUP
                </button>

                {/* ZOOM */}

                <div>

                  <div className="flex justify-between mb-3">

                    <p className="text-xs text-white/60">
                      Zoom
                    </p>

                    <p className="text-xs text-yellow-500 font-black">
                      {logoScale}%
                    </p>

                  </div>

                  <input
                    type="range"
                    min="50"
                    max="180"
                    value={logoScale}
                    onChange={(e) =>
                      setLogoScale(
                        e.target.value
                      )
                    }
                    className="w-full"
                  />

                </div>

              </>

            )}

          </div>

        </div>

      </div>

    </div>

  )
}
